import { useReducer, useMemo } from 'react';
import { useBuildPayload } from '../shared/hooks/useBuildPayload';
import { presentBuild } from './canvasBuildPresenter';
import { canvasBuildReducer, initialCanvasBuildState } from './canvasBuildReducer';
import { CanvasOrbitSurface } from './CanvasOrbitSurface';
import { CanvasDockHost } from './CanvasDockHost';
import { CanvasReleaseTray } from './CanvasReleaseTray';
import './canvas-build.css';

export function CanvasBuildPage({ workflowId }: { workflowId: string | null }) {
  const { payload, loading, error, mutate } = useBuildPayload(workflowId);
  const [state, dispatch] = useReducer(canvasBuildReducer, initialCanvasBuildState);
  const viewModel = useMemo(
    () => presentBuild(payload, state.selectedNodeId, 280),
    [payload, state.selectedNodeId]
  );

  // Wire dispatch to orbit and dock callbacks
  // Render: loading state, error state, or main layout
  // Main layout: .canvas-page with orbit center, dock right, release bottom
}
```

The page should:
1. Show loading spinner while payload is null
2. Show error state if fetch fails
3. Render orbit surface centered, dock to the right (if open), release tray at bottom
4. Pass mutate function to dock for stepper actions
5. Re-derive viewModel on every payload or selection change

RULES:
- This is the ONLY component with useReducer. All children are controlled via props.
- Use CSS layout from canvas-build.css (flex, grid as needed).
- No direct API calls — everything goes through useBuildPayload.

